	import java.util.Arrays;
	import java.util.List;

	import sailpoint.api.RequestManager;
	import sailpoint.object.Attributes;
	import sailpoint.object.Identity;
	import sailpoint.object.IdentityRequest;
	import sailpoint.object.ProvisioningPlan;
	import sailpoint.object.ProvisioningPlan.AccountRequest;
	import sailpoint.object.Request;
	import sailpoint.object.RequestDefinition;
	import sailpoint.object.Workflow;
	import sailpoint.tools.GeneralException;
	import sailpoint.workflow.StandardWorkflowHandler;
	
	
	public void scheduleWorkflow(String workflowName, String caseName, long startTime, Attributes wfArgs, String requesterId){    
      
		if (null == caseName || "".equals(caseName.trim())){
			caseName     = "Run " + workflowName;       
		}

		Workflow eventWorkflow = context.getObject(Workflow.class, workflowName);
		if (null == eventWorkflow) {
		 System.out.println("Could not find a workflow named: " + workflowName);
		 throw new GeneralException("Invalid worklfow: " + workflowName);
		}

		// Simulate the request being submitted by a user. Default: spadmin.
		Identity id = context.getObjectByName(Identity.class, requesterId);
		if (null == id) {
		 System.out.println("Could not find a requester Identity: " + requesterId);
		 throw new GeneralException("Invalid identity: " + requesterId);
		}



		// Build out a map of arguments to pass to the Request Scheduler.
		Attributes reqArgs = new Attributes();
		reqArgs.put(StandardWorkflowHandler.ARG_REQUEST_DEFINITION,sailpoint.request.WorkflowRequestExecutor.DEFINITION_NAME);
		reqArgs.put(sailpoint.workflow.StandardWorkflowHandler.ARG_WORKFLOW,workflowName);
		reqArgs.put(sailpoint.workflow.StandardWorkflowHandler.ARG_REQUEST_NAME,caseName);
		reqArgs.put( "requestName", caseName );            

		wfArgs.put("workflow", eventWorkflow.getName());

		reqArgs.putAll(wfArgs);

		// Use the Request Launcher to schedule the workflow reqeust.  This requires
		// a Request object to store the properties of the request item.
		Request req = new Request();
		RequestDefinition reqdef = context.getObject(RequestDefinition.class, "Workflow Request");
		reqdef.setDescription("Replayed Previous AccessRequest ID: "+requesterId);
    	req.setDefinition(reqdef);
		req.setEventDate( new Date(startTime));
		req.setOwner(id);
		req.setName(caseName);
		req.setAttributes( reqdef, reqArgs );
   
		RequestManager.addRequest(context, req);    
    }
	
	String workflowName="LCM Provisioning";
	String dataList = config.get("identityRequests");
	if(null == dataList) {
		throw new RuntimeException("Identity Requests can not be null");
	}
	List idenReqs = Arrays.asList(dataList.split(","));
	
	IdentityRequest idenReq=null;
	Identity identity=null;
	Attributes newWFArgs=null;
	Date today=new Date();
	for(String identReqNumber:idenReqs){
		idenReq=context.getObjectByName(IdentityRequest.class,identReqNumber);
		if(idenReq!=null){
			List plans= idenReq.getProvisionedProject().getPlans();
			ProvisioningPlan plan=new ProvisioningPlan();
			for(ProvisioningPlan dummyPlan:plans){
				plan.add(dummyPlan.getAccountRequests().get(0));
			}
			identity=context.getObjectById(Identity.class,idenReq.getTargetId());
			plan.setIdentity(identity);
			newWFArgs = new Attributes();
			newWFArgs.put("identityName",identity.getName());
			newWFArgs.put("plan",plan);
			newWFArgs.put("approvalScheme","none");
			newWFArgs.put("notificationScheme","none");
			newWFArgs.put("policyScheme","none");
			newWFArgs.put("flow","Replayed Request ("+identReqNumber+")");
			scheduleWorkflow(workflowName, null, today.getTime(), newWFArgs, "spadmin");    
		}
	}
